import itertools

def count_maximal(s, t):
    n = len(s)
    cows = list(range(n))
    barns = list(range(n))
    ans = 0
    # enumerate all subsets of cows to match? Better: iterate over all possible matchings as sets of pairs.
    # We'll generate all injections from a subset of cows to a subset of barns.
    for k in range(n+1):
        for cow_subset in itertools.combinations(range(n), k):
            for barn_subset in itertools.combinations(range(n), k):
                # permute barns to assign to cows
                for perm in itertools.permutations(barn_subset):
                    # check valid: s[cow] <= t[barn]
                    ok = True
                    for ci, bj in zip(cow_subset, perm):
                        if s[ci] > t[bj]:
                            ok = False
                            break
                    if not ok:
                        continue
                    # check maximality: no unmatched cow fits in any unmatched barn
                    unmatched_cows = [i for i in range(n) if i not in cow_subset]
                    unmatched_barns = [j for j in range(n) if j not in barn_subset]
                    maximal = True
                    for ci in unmatched_cows:
                        for bj in unmatched_barns:
                            if s[ci] <= t[bj]:
                                maximal = False
                                break
                        if not maximal:
                            break
                    if maximal:
                        ans += 1
    return ans

# test sample
